  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires finding a general scaling exponent for dissipative PDEs based on dimension n and diffusion order s, then verifying it against specific physical models.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Derive the general scaling exponent for the critical regularity or the De Giorgi type exponent in dissipative partial differential equations. Consider a general equation of the form du/dt + (u dot grad)u + (-Delta)^s u = 0 in n dimensions. Use dimensional analysis or scaling transformations to find the relationship between the exponent, the dimension n, and the fractional Laplacian order s."
    },
    {
      "label": "helper_2",
      "instructions": "Verify the derived formula for the De Giorgi exponent by calculating the specific values for the following six cases: 3D Navier-Stokes (n=3, s=1), 2D Navier-Stokes (n=2, s=1), 1D Burgers (n=1, s=1), Surface Quasi-Geostrophic equation (SQG) (n=2, s=1/2), Magnetohydrodynamics (MHD) (n=3, s=1), and fractional Navier-Stokes (n=3, s arbitrary). Ensure the formula correctly predicts the critical scaling for each."
    }
  ],
  "synthesis_brief": "Combine the general scaling law derived by helper 1 with the specific case verifications provided by helper 2 to provide the final universal formula and the table of values for the requested PDEs."
}

